import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"唤起风暴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/唤起风暴.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/唤起风暴.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/唤起风暴.md"};function _(l,e,i,p,c,b){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"唤起风暴",tabindex:"-1"},[n("唤起风暴 "),a("a",{class:"header-anchor",href:"#唤起风暴","aria-label":'Permalink to "唤起风暴"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="唤起风暴-1" tabindex="-1">唤起风暴 <a class="header-anchor" href="#唤起风暴-1" aria-label="Permalink to &quot;唤起风暴&quot;">​</a></h1><p>唤起风暴</p><p>价格：C+1250<br> 描述：《艾尔登法环》世界中存在的能赋予武器属性，战技的战灰之一。在取得时需要选定自身持有的一个武器，将战灰赋予其上。只有在装备那个武器时，才可以使用战灰的战技。<br> 这个战灰可以附着在所有的长柄武器，剑类武器，以及斧和锤上。<br> 一柄武器仅可以被赋予一个战灰。战灰所选定的武器可以在一次长休时进行变更。<br> 这个战灰可以由“战灰：回旋斩”差价升级得到。<br> 【优质】：战灰所附带的属性之一，每在力量和敏捷上合计具有6点属性，就在附加了本战灰的武器的攻击上获得1点器械加值。<br> 【战技：唤起风暴】：史东薇尔的风暴战技之一。能挥舞武器，在自身周围唤起风暴。再次发动能使出最多两次的追击。<br> 以一个整轮动作，消耗1点意志，你举起武器，一边以环形的轨迹挥舞武器，同时狂暴的气流在你的身边汹涌流动，这视为你以一个整轮动作进行了一次攻击和一次格挡。<br> 你的这次攻击可以至多以触及范围内的四个敌人为对象，并且在攻击上失去4点dp，获得额外的4个附加成功。<br> 只要你维持这个战技带来的格挡，你还具有基于格挡防御的1点全伤害吸收。<br> 此外，唤起风暴可以进行连环的追击。因此只要上一轮你使用过了唤起风暴，本轮你继续使用回旋击攻击时，你再在攻击上获得4点技艺加值，并且因为你本轮使用了唤起风暴，下一轮你使用唤起风暴时，在继承增益的基础上，由于连续的攻击掀起的狂风，你还会再攻击上获得【碾压】特性。<br> 经过这三轮后，一次完整的唤起风暴战技释放完毕，你因为连续使用唤起风暴的收益从头开始重新计算。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',5)])])}const f=r(d,[["render",_]]);export{m as __pageData,f as default};
